package agent

// execute_bead_land_test.go — Land() coordinator-pattern unit tests.
//
// These tests run against a real temp git repo so they exercise the actual
// git plumbing (update-ref, merge --no-ff, worktree add, etc.) rather than a
// mock. Each scenario asserts that the target tip advances correctly and —
// crucially for replay fidelity — that the worker's own commit is never
// rewritten. Its parent always stays BaseRev so replay sees the same inputs
// the worker saw at execution time.

import (
	"encoding/json"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/gitlock"
)

// ----------------------------------------------------------------------------
// Test helpers (real git repo fixtures)
// ----------------------------------------------------------------------------

type landTestRepo struct {
	t       *testing.T
	dir     string
	origin  string // path to a bare origin repo, or "" if no remote
	branch  string // target branch
	baseSHA string // the initial commit on the target branch
}

func newLandTestRepo(t *testing.T) *landTestRepo {
	t.Helper()
	dir := t.TempDir()
	r := &landTestRepo{t: t, dir: dir, branch: "main"}
	r.runGit("init", "-b", "main")
	r.runGit("config", "user.name", "Test")
	r.runGit("config", "user.email", "test@test.local")
	r.writeFile("README.md", "# test\n")
	r.runGit("add", "-A")
	r.runGit("commit", "-m", "init")
	r.baseSHA = r.resolveRef("refs/heads/main")
	return r
}

// newLandTestRepoWithOrigin creates a test repo whose origin is a separate
// bare repo. Used by the push-ff-only test.
func newLandTestRepoWithOrigin(t *testing.T) *landTestRepo {
	t.Helper()
	r := newLandTestRepo(t)

	bareDir := t.TempDir()
	cmd := exec.Command("git", "init", "--bare", "-b", "main", bareDir)
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("git init --bare: %s: %v", string(out), err)
	}
	r.origin = bareDir
	r.runGit("remote", "add", "origin", bareDir)
	r.runGit("push", "-u", "origin", "main")
	return r
}

func (r *landTestRepo) runGit(args ...string) string {
	r.t.Helper()
	cmd := exec.Command("git", append([]string{"-C", r.dir}, args...)...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		r.t.Fatalf("git %s: %s: %v", strings.Join(args, " "), string(out), err)
	}
	return strings.TrimSpace(string(out))
}

func (r *landTestRepo) writeFile(path, content string) {
	r.t.Helper()
	full := filepath.Join(r.dir, path)
	if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
		r.t.Fatal(err)
	}
	if err := os.WriteFile(full, []byte(content), 0o644); err != nil {
		r.t.Fatal(err)
	}
}

func (r *landTestRepo) resolveRef(ref string) string {
	r.t.Helper()
	return r.runGit("rev-parse", ref)
}

func (r *landTestRepo) syncWorkTreeFrom(fromRev string) {
	r.t.Helper()
	if err := syncWorkTreeToHeadExcludingPaths(r.dir, fromRev, nil); err != nil {
		r.t.Fatalf("sync worktree from %s: %v", fromRev, err)
	}
}

// commitOn creates a detached-head commit at baseSHA in a throwaway worktree
// and returns the new commit SHA. The commit is reachable via object store
// but not via any branch in the main repo, simulating what a worker worktree
// produces after ExecuteBead cleans up.
func (r *landTestRepo) commitOn(baseSHA, path, content, msg string) string {
	r.t.Helper()
	wt, err := os.MkdirTemp("", "land-test-wt-*")
	if err != nil {
		r.t.Fatal(err)
	}
	_ = os.RemoveAll(wt)
	r.runGit("worktree", "add", "--detach", wt, baseSHA)
	defer func() {
		r.runGit("worktree", "remove", "--force", wt)
		_ = os.RemoveAll(wt)
	}()

	if err := os.WriteFile(filepath.Join(wt, path), []byte(content), 0o644); err != nil {
		r.t.Fatal(err)
	}
	cmd := exec.Command("git", "-C", wt, "add", "-A")
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git add: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "-c", "user.name=Test", "-c", "user.email=test@test.local", "commit", "-m", msg)
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git commit: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
	out, err := cmd.Output()
	if err != nil {
		r.t.Fatalf("git rev-parse HEAD: %v", err)
	}
	sha := strings.TrimSpace(string(out))

	// Pin the commit with a temporary ref so it survives the worktree
	// cleanup. The test caller is responsible for Land()-ing it later.
	ref := fmt.Sprintf("refs/ddx/test-pins/%s", sha[:12])
	r.runGit("update-ref", ref, sha)
	return sha
}

func (r *landTestRepo) commitOnFiles(baseSHA, msg string, files map[string]string) string {
	r.t.Helper()
	wt, err := os.MkdirTemp("", "land-test-wt-*")
	if err != nil {
		r.t.Fatal(err)
	}
	_ = os.RemoveAll(wt)
	r.runGit("worktree", "add", "--detach", wt, baseSHA)
	defer func() {
		r.runGit("worktree", "remove", "--force", wt)
		_ = os.RemoveAll(wt)
	}()

	for path, content := range files {
		full := filepath.Join(wt, path)
		if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
			r.t.Fatal(err)
		}
		if err := os.WriteFile(full, []byte(content), 0o644); err != nil {
			r.t.Fatal(err)
		}
	}
	cmd := exec.Command("git", "-C", wt, "add", "-A")
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git add: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "-c", "user.name=Test", "-c", "user.email=test@test.local", "commit", "-m", msg)
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git commit: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
	out, err := cmd.Output()
	if err != nil {
		r.t.Fatalf("git rev-parse HEAD: %v", err)
	}
	sha := strings.TrimSpace(string(out))
	ref := fmt.Sprintf("refs/ddx/test-pins/%s", sha[:12])
	r.runGit("update-ref", ref, sha)
	return sha
}

func (r *landTestRepo) commitDeleteOn(baseSHA, path, msg string) string {
	r.t.Helper()
	wt, err := os.MkdirTemp("", "land-test-wt-*")
	if err != nil {
		r.t.Fatal(err)
	}
	_ = os.RemoveAll(wt)
	r.runGit("worktree", "add", "--detach", wt, baseSHA)
	defer func() {
		r.runGit("worktree", "remove", "--force", wt)
		_ = os.RemoveAll(wt)
	}()

	if err := os.Remove(filepath.Join(wt, path)); err != nil {
		r.t.Fatal(err)
	}
	cmd := exec.Command("git", "-C", wt, "add", "-A")
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git add: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "-c", "user.name=Test", "-c", "user.email=test@test.local", "commit", "-m", msg)
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git commit: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
	out, err := cmd.Output()
	if err != nil {
		r.t.Fatalf("git rev-parse HEAD: %v", err)
	}
	sha := strings.TrimSpace(string(out))
	ref := fmt.Sprintf("refs/ddx/test-pins/%s", sha[:12])
	r.runGit("update-ref", ref, sha)
	return sha
}

func writeExecuteBeadBundle(t *testing.T, root string, res *ExecuteBeadResult, extraFiles map[string]string) {
	t.Helper()
	evidenceDir := filepath.Join(root, filepath.FromSlash(res.ExecutionDir))
	if err := os.MkdirAll(evidenceDir, 0o755); err != nil {
		t.Fatal(err)
	}
	if err := writeArtifactJSON(filepath.Join(evidenceDir, "manifest.json"), map[string]string{
		"attempt_id": res.AttemptID,
		"bead_id":    res.BeadID,
	}); err != nil {
		t.Fatal(err)
	}
	if err := writeArtifactJSON(filepath.Join(evidenceDir, "result.json"), res); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(evidenceDir, "prompt.md"), []byte("# Prompt\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	for rel, content := range extraFiles {
		full := filepath.Join(evidenceDir, filepath.FromSlash(rel))
		if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
			t.Fatal(err)
		}
		if err := os.WriteFile(full, []byte(content), 0o644); err != nil {
			t.Fatal(err)
		}
	}
}

func (r *landTestRepo) commitExecuteBeadEvidence(baseSHA string, res *ExecuteBeadResult, extraFiles map[string]string) string {
	r.t.Helper()
	wt, err := os.MkdirTemp("", "land-test-evidence-wt-*")
	if err != nil {
		r.t.Fatal(err)
	}
	_ = os.RemoveAll(wt)
	r.runGit("worktree", "add", "--detach", wt, baseSHA)
	defer func() {
		r.runGit("worktree", "remove", "--force", wt)
		_ = os.RemoveAll(wt)

		if postLandErr != nil {
			err = withMainGitLock(projectRoot, "land_post_land_failure", func() error {
				var preserved *LandResult
				preserved, err = preserveIfPostLandGateFailsLocked(finalWD, req, gitOps, prep.targetRef, prep.currentTip, result.NewTip, prep.contribCount, postLandOutput, postLandErr)
				if err != nil {
					return err
				}
				result = preserved
				syncFromRev = result.NewTip
				if syncFromRev == "" {
					syncFromRev = req.ResultRev
				}
				if result != nil && syncOperatorAfterLand && syncFromRev != "" {
					syncWorkTreeToHeadGuarded(gitOps, wd, syncFromRev, operatorDirtyBeforeLand, result)
				}
				return nil
			})
			if err != nil {
				return nil, err
			}
			return result, nil
		}

		if req.EvidenceDir != "" {
			if prepareErr := prepareLandEvidence(projectRoot, finalWD, req, gitOps, result); prepareErr != nil {
				err = withMainGitLock(projectRoot, "land_post_land_finalize", func() error {
					preserved, preserveErr := preserveAfterEvidenceFailure(finalWD, req, gitOps, prep.targetRef, prep.currentTip, result.NewTip, prep.contribCount, nil, prepareErr)
					if preserveErr != nil {
						return preserveErr
					}
					result = preserved
					syncFromRev = result.NewTip
					return nil
				})
				if err != nil {
					return nil, err
				}
				return result, nil
			}
		}
		err = withMainGitLock(projectRoot, "land_post_land_finalize", func() error {
			if req.EvidenceDir != "" {
				if err := landEvidence(finalWD, prep.targetBranch, req, gitOps, result); err != nil {
					preserved, preserveErr := preserveAfterEvidenceFailure(finalWD, req, gitOps, prep.targetRef, prep.currentTip, result.NewTip, prep.contribCount, nil, err)
					if preserveErr != nil {
						return preserveErr
					}
					result = preserved
					syncFromRev = result.NewTip
					return nil
				}
				cleanupProjectEvidenceCopy(projectRoot, req.EvidenceDir)
			}
			syncFromRev = prep.currentTip
			if result != nil && syncOperatorAfterLand && syncFromRev != "" {
				syncWorkTreeToHeadGuarded(gitOps, wd, syncFromRev, operatorDirtyBeforeLand, result)
			}
			return nil
		})
		if err != nil {
			return nil, err
		}
		return result, nil
	}
}

func preserveIfPostLandGateFailsLocked(wd string, req LandRequest, gitOps LandingGitOps, targetRef, preLandTip, landedTip string, contribCount int, output string, gateErr error) (*LandResult, error) {
	if len(req.PostLandCommand) == 0 {
		return nil, nil
	}
	preserveRef := landIterationRef(req.BeadID, req.AttemptID, preLandTip)
	if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
		return nil, fmt.Errorf("preserving %s after post-land gate: %w", preserveRef, upErr)
	}
	if revertErr := gitOps.UpdateRefTo(wd, targetRef, preLandTip, landedTip); revertErr != nil {
		return nil, fmt.Errorf("restoring %s to %s after post-land gate failed: %w", targetRef, preLandTip, revertErr)
	}

	reason := fmt.Sprintf("post-land gate failed: %s: %v", strings.Join(req.PostLandCommand, " "), gateErr)
	if trimmed := strings.TrimSpace(output); trimmed != "" {
		reason += ": " + truncatePostLandGateOutput(trimmed)
	}
	result := &LandResult{
		Status:            "preserved",
		PreserveRef:       preserveRef,
		Reason:            reason,
		TargetBranch:      req.TargetBranch,
		MergedCommitCount: contribCount,
	}
	return result, nil
}

func preserveAfterEvidenceFailure(wd string, req LandRequest, gitOps LandingGitOps, targetRef, preLandTip, landedTip string, contribCount int, dirtyBefore []string, evidenceErr error) (*LandResult, error) {
	preserveRef := landIterationRef(req.BeadID, req.AttemptID, preLandTip)
	if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
		return nil, fmt.Errorf("preserving %s after evidence commit failure: %w", preserveRef, upErr)
	}
	if landedTip != "" {
		if revertErr := gitOps.UpdateRefTo(wd, targetRef, preLandTip, landedTip); revertErr != nil {
			return nil, fmt.Errorf("restoring %s to %s after evidence commit failed: %w", targetRef, preLandTip, revertErr)
		}
	}
	result := &LandResult{
		Status:            "preserved",
		PreserveRef:       preserveRef,
		Reason:            "evidence commit failed: " + evidenceErr.Error(),
		TargetBranch:      req.TargetBranch,
		MergedCommitCount: contribCount,
	}
	return result, nil
}

func runPostLandCommand(wd string, command []string) (string, error) {
	if len(command) == 0 {
		return "", nil
	}
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Minute)
	defer cancel()
	cmd := exec.CommandContext(ctx, command[0], command[1:]...)
	cmd.Dir = wd
	out, err := cmd.CombinedOutput()
	if ctx.Err() == context.DeadlineExceeded {
		return string(out), ctx.Err()
	}
	return string(out), err
}

func truncatePostLandGateOutput(output string) string {
	const max = 2048
	if len(output) <= max {
		return output
	}
	return output[:max] + "...(truncated)"
}

type largeDeletionFinding struct {
	Path    string
	Deleted int
}

func preserveIfLargeDeletion(wd string, req LandRequest, gitOps LandingGitOps, currentTip string, contribCount int) (*LandResult, error) {
	threshold := largeDeletionLineThreshold(req)
	finding, found, err := largestDeletionFinding(gitOps, wd, req.BaseRev, req.ResultRev, threshold)
	if err != nil {
		return nil, err
	}
	if !found {
		return nil, nil
	}
	ack, err := landHasLargeDeletionAcknowledgement(wd, req.BaseRev, req.ResultRev)
	if err == nil && ack {
		return nil, nil
	}

	preserveRef := landIterationRef(req.BeadID, req.AttemptID, currentTip)
	if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
		return nil, fmt.Errorf("preserving %s after large-deletion gate: %w", preserveRef, upErr)
	}
	return &LandResult{
		Status:            "preserved",
		PreserveRef:       preserveRef,
		Reason:            fmt.Sprintf("large-deletion gate: %s deleted %d lines (threshold %d) without intentional large deletion acknowledgement", finding.Path, finding.Deleted, threshold),
		TargetBranch:      req.TargetBranch,
		MergedCommitCount: contribCount,
	}, nil
}

func largeDeletionLineThreshold(req LandRequest) int {
	if req.LargeDeletionLineThreshold > 0 {
		return req.LargeDeletionLineThreshold
	}
	return defaultLargeDeletionLineThreshold
}

func largestDeletionFinding(gitOps LandingGitOps, wd, baseRev, resultRev string, threshold int) (largeDeletionFinding, bool, error) {
	raw, err := gitOps.DiffNumstat(wd, baseRev, resultRev)
	if err != nil {
		return largeDeletionFinding{}, false, fmt.Errorf("checking large deletions: %w", err)
	}
	var largest largeDeletionFinding
	for _, line := range strings.Split(strings.TrimSpace(raw), "\n") {
		if strings.TrimSpace(line) == "" {
			continue
		}
		parts := strings.SplitN(line, "\t", 3)
		if len(parts) != 3 || parts[1] == "-" {
			continue
		}
		deleted, parseErr := strconv.Atoi(parts[1])
		if parseErr != nil {
			continue
		}
		if deleted > threshold && deleted > largest.Deleted {
			largest = largeDeletionFinding{Path: parts[2], Deleted: deleted}
		}
	}
	return largest, largest.Path != "", nil
}

func landHasLargeDeletionAcknowledgement(wd, baseRev, resultRev string) (bool, error) {
	out, err := internalgit.Command(context.Background(), wd, "log", "--format=%B", baseRev+".."+resultRev).CombinedOutput()
	if err != nil {
		return false, fmt.Errorf("checking large-deletion acknowledgement: %s: %w", strings.TrimSpace(string(out)), err)
	}
	msg := strings.ToLower(string(out))
	for _, marker := range []string{
		"intentional large deletion",
		"intentional file removal",
		"intentional file deletion",
	} {
		if strings.Contains(msg, marker) {
			return true, nil
		}
	}
	return false, nil
}

type syntaxSanityFinding struct {
	Path   string
	Reason string
}

func preserveIfSyntaxSanityFails(wd string, req LandRequest, gitOps LandingGitOps, currentTip string, contribCount int) (*LandResult, error) {
	finding, found, err := syntaxSanityFindingForResult(gitOps, wd, req.BaseRev, req.ResultRev)
	if err != nil {
		return nil, err
	}
	if !found {
		return nil, nil
	}

	preserveRef := landIterationRef(req.BeadID, req.AttemptID, currentTip)
	if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
		return nil, fmt.Errorf("preserving %s after syntax sanity gate: %w", preserveRef, upErr)
	}
	return &LandResult{
		Status:            "preserved",
		PreserveRef:       preserveRef,
		Reason:            fmt.Sprintf("syntax sanity gate: %s: %s", finding.Path, finding.Reason),
		TargetBranch:      req.TargetBranch,
		MergedCommitCount: contribCount,
	}, nil
}

func syntaxSanityFindingForResult(gitOps LandingGitOps, wd, baseRev, resultRev string) (syntaxSanityFinding, bool, error) {
	paths, err := gitOps.DiffNameOnly(wd, baseRev, resultRev)
	if err != nil {
		return syntaxSanityFinding{}, false, err
	}
	for _, path := range paths {
		result, ok, err := gitFileAt(wd, resultRev, path)
		if err != nil {
			return syntaxSanityFinding{}, false, err
		}
		if !ok {
			continue // deleted files are handled by deletion gates, not syntax checks.
		}
		base, _, err := gitFileAt(wd, baseRev, path)
		if err != nil {
			return syntaxSanityFinding{}, false, err
		}
		if reason, bad := syntaxSanityFailure(path, base, result); bad {
			return syntaxSanityFinding{Path: path, Reason: reason}, true, nil
		}
	}
	return syntaxSanityFinding{}, false, nil
}

func gitFileAt(wd, rev, path string) ([]byte, bool, error) {
	out, err := internalgit.Command(context.Background(), wd, "show", rev+":"+path).CombinedOutput()
	if err != nil {
		if strings.Contains(string(out), "does not exist") || strings.Contains(string(out), "exists on disk, but not in") {
			return nil, false, nil
		}
		return nil, false, fmt.Errorf("reading %s at %s: %s: %w", path, rev, strings.TrimSpace(string(out)), err)
	}
	return out, true, nil
}

func syntaxSanityFailure(path string, base, result []byte) (string, bool) {
	switch strings.ToLower(filepath.Ext(path)) {
	case ".json":
		var v any
		if err := json.Unmarshal(result, &v); err != nil {
			return "invalid JSON: " + err.Error(), true
		}

